) VALUES
('general_small_business', 'General Small Business', 'IB-H2 Failure: No defined buyer profile', 'Owner cannot describe ideal customer in one sentence; marketing spreads thin across mismatched leads.', 'Symptoms: leads do not close, ad spend feels random, referrals strongest. Hidden cause: no documented ICP. Evidence: lead quality unknown, no source attribution. Likely score impact: −15 to −30. Diagnostic Qs: Who is your best 3-month customer? Why did they buy? Repair-map: define ICP + qualifier.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'demand_generation', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1010, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: Weak lead qualification', 'Every lead is treated equally; sales time consumed by tire-kickers.', 'Symptoms: long quoting cycle, low close rate, owner doing all qualifying. Hidden cause: no qualifier checklist. Evidence: no disqualified-lead log. Repair-map: add 3-question qualifier.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'revenue_conversion', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1020, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: Owner-only sales', 'All deals close through the owner; team cannot quote or negotiate.', 'Symptoms: deals stall when owner travels. Hidden cause: pricing/decision logic in owner''s head. Evidence: no written pricing rules. Repair-map: write decision rights.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'owner_independence', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1030, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: Poor follow-up', 'Quotes/leads sit without contact for days; pipeline rot.', 'Symptoms: lost deals ''reappear'' months later. Evidence: no follow-up cadence in CRM. Repair-map: 3-touch follow-up SOP.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'revenue_conversion', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1040, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: Unclear pricing', 'Pricing varies by mood, customer, or memory.', 'Evidence: same service quoted at different prices same week. Repair-map: pricing matrix + minimum margin floor.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1050, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: No SOPs', 'Work performed from memory; quality drifts when staff changes.', 'Evidence: no documented procedures, training is shadowing only. Repair-map: top-5 SOP starter set.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'operational_efficiency', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1060, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: Delivery inconsistency', 'Customer experience depends on which staff member handled them.', 'Evidence: review variance, repeat issues by employee. Repair-map: standardized delivery checklist.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'operational_efficiency', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1070, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: Cash flow blindness', 'Owner uses bank balance as profitability signal.', 'Evidence: no 13-week cash forecast, surprise shortfalls. Repair-map: weekly cash dashboard.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1080, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: No performance dashboard', 'No single weekly view of revenue, leads, jobs, cash.', 'Evidence: numbers reviewed quarterly or never. Repair-map: 1-page weekly scoreboard.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1090, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('general_small_business', 'General Small Business', 'IB-H2 Failure: No delegation structure', 'Owner is decision bottleneck for routine work.', 'Evidence: questions queue waiting for owner. Repair-map: decision-rights matrix.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'owner_independence', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1100, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: Owner is the bottleneck', 'Estimating, scheduling, and invoicing all funnel through the owner.', 'Evidence: jobs slip when owner is on a job, no written estimating rules. Repair-map: estimator role + decision rights.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'owner_independence', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1010, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: Quoting delay causes lost jobs', 'Multi-day delay between request and quote; competitor wins on speed.', 'Evidence: average quote-out time > 48h, lost-quote reason ''no response''. Repair-map: 24h quote SLA.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'revenue_conversion', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1020, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: No job costing', 'Per-job labor and materials never reconciled to estimate.', 'Evidence: no actual-vs-estimate by job, gross margin estimated from gut. Repair-map: per-job costing template.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1030, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: Schedule chaos', 'Scheduling lives in head/text; double-bookings and missed jobs.', 'Evidence: no shared dispatch board, customer status updates ad-hoc. Repair-map: dispatch board + confirmation cadence.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'operational_efficiency', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1040, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: Callback / rework creep', 'Rework not tracked; same failures repeat.', 'Evidence: no callback log, warranty work absorbs margin. Repair-map: callback log + root-cause review.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'operational_efficiency', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1050, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: Lead source overdependence', 'One channel (referrals or one ad source) drives most leads.', 'Evidence: no source attribution, sudden quiet weeks unexplained. Repair-map: source tagging + 2nd channel pilot.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'demand_generation', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1060, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: No follow-up process', 'Quotes sent and never re-touched.', 'Evidence: no follow-up in CRM, lost-bid analysis missing. Repair-map: 3-touch follow-up SOP.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'revenue_conversion', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1070, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
