('trades_services', 'Trades / Services', 'IB-H2 Failure: Unpaid invoices / AR drag', 'Aged AR > 60 days erodes cash.', 'Evidence: AR aging report not run, deposits not standard. Repair-map: deposit policy + AR cadence.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1090, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: Technician dependency', 'One technician holds the relationships and the methods.', 'Evidence: customers ask for that tech by name, no documented procedures. Repair-map: cross-train + SOPs.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'owner_independence', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1100, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('trades_services', 'Trades / Services', 'IB-H2 Failure: Service area profitability blind spots', 'Some service lines lose money but get prioritized.', 'Evidence: no margin per service line. Repair-map: service-line P&L cut.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1110, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Labor cost creep', 'Labor % drifts above target without anyone noticing weekly.', 'Evidence: labor % computed monthly or never, schedules built from memory. Repair-map: weekly labor target + sales-driven schedule.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1010, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Food cost creep', 'Vendor price increases pass through silently.', 'Evidence: no menu costing review > 90 days, recipe cards inconsistent. Repair-map: monthly cost recheck on top-20 SKUs.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1020, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Poor menu engineering', 'Menu mix not analyzed; star/dog items unidentified.', 'Evidence: no contribution-margin sort by item. Repair-map: menu engineering matrix.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'revenue_conversion', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1030, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Spoilage / yield loss', 'Prep over-built, waste not logged.', 'Evidence: no waste sheet, end-of-day prep dumped. Repair-map: prep par + waste log.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'operational_efficiency', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1040, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Weak table turns / throughput', 'Peak hours leave revenue on the table.', 'Evidence: no average ticket-time tracking, server stations unbalanced. Repair-map: ticket-time SLA + station balance.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'operational_efficiency', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1050, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Owner-dependent operations', 'Owner expedites, schedules, and reconciles personally.', 'Evidence: shifts collapse when owner absent. Repair-map: shift lead role + checklist.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'owner_independence', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1060, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Inconsistent prep / process standards', 'Recipes executed by memory; quality varies by cook.', 'Evidence: no recipe cards posted, plating varies. Repair-map: recipe cards + line training.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'operational_efficiency', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1070, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Inventory leakage', 'Inventory variance not reconciled; theft/over-portioning hidden.', 'Evidence: no weekly count vs theoretical usage. Repair-map: weekly count cycle.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1080, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: No daily break-even visibility', 'Owner can''t say what today needs to cover.', 'Evidence: no daily break-even card. Repair-map: posted daily break-even.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'financial_visibility', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1090, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
('restaurant_food_service', 'Restaurant / Food Service', 'IB-H2 Failure: Review / reputation dependency', 'One bad review week tanks bookings; no proactive review flow.', 'Evidence: no review-request automation. Repair-map: post-visit review request.', 'Industry-aware example only. Does not replace owner judgment or qualified advisors.', 'risk_signal', 'demand_generation', 'shared_support', 'admin_review', 'industry_aware_outputs', 'active', false, true, 1100, '{"anchor": "failure_library", "ib_h2": true}'::jsonb),
