('general_small_business', 'Qualified lead', 'A prospect that matches ICP and has expressed need + ability to buy.', 'All industries share this term; the qualifier criteria differ by vertical.', 'revenue_conversion', 'A prospect that matches ICP and has expressed need + ability to buy.', false),
('general_small_business', 'Owner bottleneck', 'Routine decisions queued waiting for the owner.', 'Same meaning across verticals; manifests differently.', 'owner_independence', 'Routine decisions queued waiting for the owner.', false),
('general_small_business', 'Recurring revenue', 'Predictable repeat revenue (subscription, retainer, contract).', 'Different mechanism per vertical; same concept.', 'financial_visibility', 'Predictable repeat revenue (subscription, retainer, contract).', false),
('general_small_business', 'Gross margin', 'Revenue minus direct cost of delivery, before overhead.', 'Direct-cost definition varies by vertical.', 'financial_visibility', 'Revenue minus direct cost of delivery, before overhead.', false),
('general_small_business', 'Break-even point', 'Revenue level where contribution covers fixed cost.', 'Calculated daily in restaurants, monthly elsewhere.', 'financial_visibility', 'Revenue level where contribution covers fixed cost.', false),
('general_small_business', 'Delegation', 'Documented authority to act without owner approval.', 'Same across verticals.', 'owner_independence', 'Documented authority to act without owner approval.', false),
('general_small_business', 'SOP coverage', 'Share of repeated work covered by a written procedure.', 'Same across verticals; varies in granularity.', 'operational_efficiency', 'Share of repeated work covered by a written procedure.', false),
('general_small_business', 'Follow-up process', 'A defined cadence and owner for re-touching open leads.', 'Different channels per vertical, same concept.', 'revenue_conversion', 'A defined cadence and owner for re-touching open leads.', false),
('general_small_business', 'Service line profitability', 'Margin attributed to a specific service or product line.', 'Vertical-specific cuts (job, menu item, SKU, category).', 'financial_visibility', 'Margin attributed to a specific service or product line.', false),
('general_small_business', 'Cash runway', 'Weeks the business can operate at current burn.', 'Same across verticals.', 'financial_visibility', 'Weeks the business can operate at current burn.', false),
('trades_services', 'Quote-to-close', 'Won jobs / quotes sent.', 'Trades-specific; restaurants don''t quote individual orders.', 'revenue_conversion', 'Won jobs / quotes sent.', false),
('trades_services', 'Callback', 'Return visit to fix a prior job at no charge.', 'Trades-specific.', 'operational_efficiency', 'Return visit to fix a prior job at no charge.', false),
('trades_services', 'Job costing', 'Reconciling actual labor + materials per job to estimate.', 'Trades/construction-specific cut.', 'financial_visibility', 'Reconciling actual labor + materials per job to estimate.', false),
('trades_services', 'Service area', 'Geographic radius the crew operates in.', 'Trades-specific.', 'operational_efficiency', 'Geographic radius the crew operates in.', false),
('trades_services', 'Dispatch capacity', 'Available crew-hours that can be booked.', 'Trades/field-services specific.', 'operational_efficiency', 'Available crew-hours that can be booked.', false),
('trades_services', 'Technician utilization', 'Billable hours divided by available hours.', 'Trades-specific.', 'operational_efficiency', 'Billable hours divided by available hours.', false),
('trades_services', 'Parts availability', 'Whether crews carry/stock required parts.', 'Trades-specific.', 'operational_efficiency', 'Whether crews carry/stock required parts.', false),
