('restaurant_food_service', 'Table turns', 'Average parties served per table per shift.', 'Restaurant-specific.', 'operational_efficiency', 'Average parties served per table per shift.', false),
('restaurant_food_service', 'Ticket time', 'Time from order entry to delivery.', 'Restaurant-specific.', 'operational_efficiency', 'Time from order entry to delivery.', false),
('restaurant_food_service', 'Menu engineering', 'Sorting items by popularity and contribution margin.', 'Restaurant-specific framework.', 'revenue_conversion', 'Sorting items by popularity and contribution margin.', false),
('restaurant_food_service', 'Spoilage', 'Inventory lost to over-prep or expiration.', 'Restaurant-specific.', 'operational_efficiency', 'Inventory lost to over-prep or expiration.', false),
