('restaurant_food_service', 'Contribution margin', 'Item sales minus item-level direct cost.', 'Used for menu engineering specifically.', 'financial_visibility', 'Item sales minus item-level direct cost.', false),
('restaurant_food_service', 'Vendor ordering', 'Recurring order cadence with primary vendors.', 'Restaurant-specific cadence.', 'operational_efficiency', 'Recurring order cadence with primary vendors.', false),
('retail', 'Sell-through', 'Units sold / units bought, by buying cycle.', 'Retail-specific.', 'revenue_conversion', 'Units sold / units bought, by buying cycle.', false),
('retail', 'Inventory turnover', 'Annualized COGS divided by average inventory.', 'Retail-specific cut.', 'operational_efficiency', 'Annualized COGS divided by average inventory.', false),
