-- IB-H2: synthetic case study seed (training only — not real proof)
INSERT INTO public.industry_case_studies (
  industry_key, business_type, case_name, approximate_score, score_band, gear_scores,
  symptoms, evidence, failure_patterns_detected, benchmark_anchors_involved,
  admin_interpretation, client_safe_summary, likely_repair_map_priorities,
  suggested_next_diagnostic_questions, what_not_to_overpromise, is_synthetic, not_real_client, client_visible, display_label
) VALUES
